"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { useState } from "react";
import { Menu, X, Home, Search, Heart, PlusCircle, User, LogIn } from "lucide-react";
import { cn } from "@/lib/utils";

export default function Navbar() {
  const [open, setOpen] = useState(false);
  const pathname = usePathname();

  const navLinks = [
    { href: "/listings", label: "Chèche Kay", icon: Search },
    { href: "/dashboard/favorites", label: "Favori", icon: Heart },
    { href: "/dashboard/new-listing", label: "Poste Anons", icon: PlusCircle },
  ];

  return (
    <header className="sticky top-0 z-50 bg-white/95 backdrop-blur-md border-b border-slate-100 shadow-sm">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">
          {/* Logo */}
          <Link href="/" className="flex items-center gap-2 group">
            <div className="w-9 h-9 bg-gradient-to-br from-caribbean-600 to-caribbean-800 rounded-xl flex items-center justify-center shadow-sm group-hover:scale-105 transition-transform">
              <Home className="w-5 h-5 text-white" />
            </div>
            <span className="text-xl font-bold text-slate-900">
              Kay<span className="text-caribbean-600">Sid</span>
            </span>
          </Link>

          {/* Desktop nav */}
          <nav className="hidden md:flex items-center gap-1">
            {navLinks.map(({ href, label, icon: Icon }) => (
              <Link
                key={href}
                href={href}
                className={cn(
                  "flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all",
                  pathname.startsWith(href)
                    ? "bg-caribbean-50 text-caribbean-700"
                    : "text-slate-600 hover:bg-slate-50 hover:text-slate-900"
                )}
              >
                <Icon className="w-4 h-4" />
                {label}
              </Link>
            ))}
          </nav>

          {/* Auth buttons */}
          <div className="hidden md:flex items-center gap-2">
            <Link href="/login" className="btn-secondary text-sm py-2 px-4">
              <LogIn className="w-4 h-4" />
              Konekte
            </Link>
            <Link href="/register" className="btn-primary text-sm py-2 px-4">
              <User className="w-4 h-4" />
              Enskri
            </Link>
          </div>

          {/* Mobile hamburger */}
          <button
            className="md:hidden p-2 rounded-lg text-slate-600 hover:bg-slate-100 transition-colors"
            onClick={() => setOpen(!open)}
            aria-label="Menu"
          >
            {open ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
          </button>
        </div>
      </div>

      {/* Mobile menu */}
      {open && (
        <div className="md:hidden border-t border-slate-100 bg-white px-4 pt-3 pb-4 space-y-1">
          {navLinks.map(({ href, label, icon: Icon }) => (
            <Link
              key={href}
              href={href}
              onClick={() => setOpen(false)}
              className={cn(
                "flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-medium transition-all",
                pathname.startsWith(href)
                  ? "bg-caribbean-50 text-caribbean-700"
                  : "text-slate-700 hover:bg-slate-50"
              )}
            >
              <Icon className="w-5 h-5" />
              {label}
            </Link>
          ))}
          <div className="pt-3 border-t border-slate-100 flex flex-col gap-2">
            <Link href="/login" onClick={() => setOpen(false)} className="btn-secondary text-sm justify-center">
              <LogIn className="w-4 h-4" />
              Konekte
            </Link>
            <Link href="/register" onClick={() => setOpen(false)} className="btn-primary text-sm justify-center">
              <User className="w-4 h-4" />
              Enskri Gratis
            </Link>
          </div>
        </div>
      )}
    </header>
  );
}
